import axios from 'axios';
import {BASE_PATH_APIS} from '../../utils/constants';

class BulkUploadAddShipmentService {

    async fetchBulkUploadAddShipmentConfig(id) {
        try {
            const response = await axios.get(BASE_PATH_APIS.basePathForAPIS+'/app/rest/label_generation/setting/fetch_lg_bulk_upload_config?id='+id);
            return response;
        } catch (error) {

        }
        return null;
    }

    async saveBulkUploadAddShipmentConfig(lgBulkUploadSettingDto) {
        try {
            const response = await axios.post(BASE_PATH_APIS.basePathForAPIS+'/app/rest/label_generation/setting/lg_bulk_upload', lgBulkUploadSettingDto);
            return response;
        } catch (error) {

        }
        return null;
    }

}

export const bulkUploadAddShipmentService = new BulkUploadAddShipmentService();
